mapper.select:
SELECT menu_id, tenant_id, menu_nm, menu_url, menu_icon, sort_order, parent_menu_id, use_yn, reg_dt, upd_dt
FROM tb_menu
WHERE menu_id = #{menuId}
AND tenant_id = #{tenantId}
AND use_yn = 'Y'

SELECT menu_id, tenant_id, menu_nm, menu_url, menu_icon, sort_order, parent_menu_id, use_yn, reg_dt, upd_dt
FROM tb_menu
WHERE tenant_id = #{tenantId}

    AND use_yn = #{useYn}

ORDER BY sort_order ASC, reg_dt DESC

SELECT menu_id, tenant_id, menu_nm, menu_url, menu_icon, sort_order, parent_menu_id, use_yn, reg_dt, upd_dt
FROM tb_menu
WHERE tenant_id = #{tenantId}

    AND use_yn = #{useYn}


    AND menu_nm LIKE CONCAT('%', #{searchKeyword}, '%')

ORDER BY sort_order ASC, reg_dt DESC

    LIMIT #{startRow}, #{pageSize}

